import 'dart:convert';

import '../../gateway/navivox_gateway_protocol.dart';

String navivoxGatewayNoActiveTurnMessage({required bool stop}) {
  return stop ? 'No active turn to stop.' : 'No active turn to cancel.';
}

String navivoxGatewayTurnControlSubmittedMessage({required bool stop}) {
  return stop
      ? 'Stop requested. Started side effects may still exist.'
      : 'Cancel requested. Started side effects may still exist.';
}

String navivoxGatewayTurnControlFrame({
  required bool stop,
  required String requestId,
  required String sessionId,
}) {
  final message = stop
      ? NavivoxGatewayMessage.stopTurn(
          requestId: requestId,
          sessionId: sessionId,
        )
      : NavivoxGatewayMessage.cancelTurn(
          requestId: requestId,
          sessionId: sessionId,
        );
  return jsonEncode(message.body);
}

import 'dart:convert';

import '../../gateway/navivox_gateway_protocol.dart';
import '../contracts/navivox_channel.dart';

/// Builds gateway turn metadata consistently for text and voice submissions.
///
/// Keeping the profile/routing field names in one place prevents the text and
/// voice paths from drifting when the gateway metadata contract evolves.
Map<String, Object?> navivoxGatewayTurnMetadata({
  required NavivoxProfileContact? profile,
  required NavivoxProfileRoutingSelection? routing,
}) {
  return {
    'client': 'navivox',
    'platform': 'flutter',
    if (profile != null) ...{
      'server_id': profile.serverId,
      'profile_id': profile.profileId,
    },
    if (routing?.workspace != null) 'workspace': routing!.workspace,
    if (routing?.provider != null) 'provider_id': routing!.provider,
    if (routing?.channel != null) 'channel_id': routing!.channel,
  };
}

/// Encodes the shared gateway start-turn wire contract.
///
/// Text and voice submissions differ in their local message state, but both must
/// send the same start_turn envelope and metadata shape to the gateway.
String navivoxGatewayStartTurnFrame({
  required String requestId,
  required String? sessionId,
  required String text,
  required NavivoxProfileContact? profile,
  required NavivoxProfileRoutingSelection? routing,
}) {
  return jsonEncode(
    NavivoxGatewayMessage.startTurn(
      requestId: requestId,
      sessionId: sessionId,
      text: text,
      metadata: navivoxGatewayTurnMetadata(profile: profile, routing: routing),
    ).body,
  );
}

import '../contracts/navivox_channel.dart';
import '../contracts/navivox_message_scope.dart';
import 'gateway_turn_metadata_policy.dart';
import '../../protocol/navivox_event.dart';

/// Builds local user transcript messages for turns sent to the gateway.
///
/// Text and voice submissions both create a user-visible transcript entry before
/// sending the shared start_turn frame. Centralizing the message construction
/// keeps profile scope and voice payload handling aligned across input modes.
NavivoxChatMessage navivoxGatewayUserTurnMessage({
  required String id,
  required String text,
  required DateTime createdAt,
  required NavivoxMessageScope scope,
  NavivoxVoiceMessage? voice,
}) {
  return NavivoxChatMessage(
    id: id,
    author: NavivoxMessageAuthor.user,
    kind: voice == null ? NavivoxMessageKind.text : NavivoxMessageKind.voice,
    createdAt: createdAt,
    text: text,
    serverId: scope.serverId,
    profileId: scope.profileId,
    voice: voice,
  );
}

/// Bundles the local user transcript entry with the gateway start-turn frame.
///
/// Text and voice turns share this submission contract: create the durable local
/// message with the active profile scope, then send the same start_turn frame to
/// the gateway. Keeping both artifacts together prevents the two input paths
/// from diverging when the turn wire contract changes.
({NavivoxChatMessage message, String frame}) navivoxGatewayUserTurnSubmission({
  required String requestId,
  required String? sessionId,
  required String text,
  required DateTime createdAt,
  required NavivoxProfileContact? profile,
  required NavivoxProfileRoutingSelection? routing,
  NavivoxVoiceMessage? voice,
}) {
  return (
    message: navivoxGatewayUserTurnMessage(
      id: requestId,
      text: text,
      createdAt: createdAt,
      scope: navivoxMessageScope(
        serverId: profile?.serverId,
        profileId: profile?.profileId,
      ),
      voice: voice,
    ),
    frame: navivoxGatewayStartTurnFrame(
      requestId: requestId,
      sessionId: sessionId,
      text: text,
      profile: profile,
      routing: routing,
    ),
  );
}

